node.warn("payload nhận được: " + JSON.stringify(msg.payload));

if (msg.payload && msg.payload.state) {
    global.set("lightState", msg.payload.state);
    msg.payload = { success: true, state: msg.payload.state };
}
return msg;

msg.payload = {
    state: global.get("lightState") || "OFF" // ✅ trả về "ON"/"OFF", mặc định "OFF"
};
return msg;

msg.payload = {
    state: "on"
};
return msg;

var device = msg.req.params.device;
var cmd = msg.payload;
var DB ="https://mysmarthome-13774-default-rtdb.asia-southeast1.firebasedatabase.app/";

// lấy state cũ
var cur = flow.get('living_' + device) || { state: 'off' };

// ===== XỬ LÝ THEO DEVICE =====

// QUẠT
if (device === 'fan' || device === 'fan1' || device === 'fan-ceil') {
    if (!cur.speed) cur.speed = 1;
    if (cmd.state) cur.state = cmd.state;
    if (cmd.speed) cur.speed = parseInt(cmd.speed);
}

// ĐIỀU HOÀ
else if (device === 'ac1') {
    if (!cur.temperature) cur.temperature = 25;
    if (cmd.state) cur.state = cmd.state;

    if (cmd.temperature !== undefined) {
        var t = parseInt(cmd.temperature);
        cur.temperature = Math.max(16, Math.min(30, t));
    }
}

// THIẾT BỊ ON/OFF
else {
    if (cmd.state) cur.state = cmd.state;
}

// lưu lại state
flow.set('living_' + device, cur);

// ===== MQTT =====
msg.topic = 'home/living/' + device;
msg.payload = cur;

// ===== FIREBASE =====
var msgFirebase = {
    method: "PATCH",
    url: DB + "/living_room/" + device + ".json",
    headers: { "Content-Type": "application/json" },
    payload: {
        state: cur.state,
        speed: cur.speed || null,
        temperature: cur.temperature || null,
        timestamp: new Date().toISOString()
    }
};

// ===== RESPONSE =====
var msgRes = {
    payload: {
        success: true,
        device: device,
        data: cur
    }
};

return [msg, msgRes,msgFirebase];

