msg.payload = { value: smoke };
return msg;

const temp = Math.floor(Math.random() * 40) + 20;

const pccc = global.get('pccc') || {};
pccc.temperature = temp;
pccc.alert = pccc.smoke >= 1 || temp >= 50;
pccc.alertMsg = pccc.alert ? 'Cảnh báo!' : 'An toàn';
global.set('pccc', pccc);

msg.payload = { value: temp };
return msg;

var value = msg.payload.value;
global.set("smoke", value);

if (value === 1) {
    global.set("alarm", true);
